import{_ as i,o as a,c as e,a3 as t}from"./chunks/framework.aYYe0dfI.js";const c=JSON.parse('{"title":"clore::generate::cache::normalizetextforhashing","description":"该函数通过两个阶段实现文本规范化。第一阶段从前向后扫描输入并跳过所有前导空白字符（使用 std::isspace 检查每个字符），因此只保留第一个非空白字符之后的文本。第二阶段从第一个非空白字符开始遍历剩余字符：遇到空白字符时，仅设置一个布尔标记 prev_space，不直接向结果追加空白；遇到非空白字符时，若 prev_space 为真且结果非空，则在追加该字符前先插入一个空格，然后重置标记。这一逻辑将任意长度的连续空白序列压缩为一个空格，同时确保结果字符串不会以空格开头（因为前导空白已跳过）且末尾不会有多余空格（只有当非空白字符之后有空白时才可能追加空格，而末尾空白序列永远不会触发追加）。整个过程完全基于标准库函数 std::isspace 和 std::string 的 reserve、push_back，无需其他外部依赖。","frontmatter":{"title":"clore::generate::cache::normalizetextforhashing","description":"该函数通过两个阶段实现文本规范化。第一阶段从前向后扫描输入并跳过所有前导空白字符（使用 std::isspace 检查每个字符），因此只保留第一个非空白字符之后的文本。第二阶段从第一个非空白字符开始遍历剩余字符：遇到空白字符时，仅设置一个布尔标记 prev_space，不直接向结果追加空白；遇到非空白字符时，若 prev_space 为真且结果非空，则在追加该字符前先插入一个空格，然后重置标记。这一逻辑将任意长度的连续空白序列压缩为一个空格，同时确保结果字符串不会以空格开头（因为前导空白已跳过）且末尾不会有多余空格（只有当非空白字符之后有空白时才可能追加空格，而末尾空白序列永远不会触发追加）。整个过程完全基于标准库函数 std::isspace 和 std::string 的 reserve、push_back，无需其他外部依赖。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/generate/functions/normalize-text-for-hashing.md","filePath":"zh/clore/modules/generate/functions/normalize-text-for-hashing.md"}'),n={name:"zh/clore/modules/generate/functions/normalize-text-for-hashing.md"};function h(l,s,p,k,r,d){return a(),e("div",null,[...s[0]||(s[0]=[t("",18)])])}const o=i(n,[["render",h]]);export{c as __pageData,o as default};
